INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'consulting_agreement',
  'us_california',
  1,
  'Consulting Agreement (California)',
  'This Consulting Agreement (this “Agreement”) is entered into as of {{effective_date}} (the “Effective Date”) by and between {{party_a_company}}, with an address at {{party_a_address}} (“Client”), and {{party_b_company}}, with an address at {{party_b_address}} (“Consultant”). Client and Consultant may be referred to individually as a “Party” and collectively as the “Parties.”',
  'WHEREAS, Client desires to engage Consultant to provide advisory and consulting services in connection with {{project_name}}; and

WHEREAS, Consultant represents that Consultant has the expertise to perform such services; and

WHEREAS, the Parties desire to set forth the terms and conditions governing Consultant’s engagement.

NOW, THEREFORE, in consideration of the mutual covenants and promises contained herein, the Parties agree as follows:',
  '[{"id":"engagement_scope","title":"1. ENGAGEMENT; SCOPE OF SERVICES","content":"1.1 Engagement. Client hereby engages Consultant to provide the services described in this Agreement, and Consultant accepts such engagement, subject to the terms and conditions herein.\n\n1.2 Scope of Services. Consultant will perform the following services (the “Services”): {{services_description}}.\n\n1.3 Standard of Performance. Consultant will perform the Services in a professional and workmanlike manner consistent with generally accepted industry standards for similar services.\n\n1.4 No Authority to Bind. Consultant has no authority to enter into contracts or make commitments on Client’s behalf unless expressly authorized in a writing signed by Client.\n\n1.5 Client Responsibilities. Client will timely provide reasonable access to information, personnel, and materials reasonably necessary for Consultant to perform the Services. Consultant is not responsible for delays caused by Client’s failure to provide such access or materials.\n\n1.6 Changes to Scope. Any change to the Services, assumptions, timelines, or Deliverables (as defined below) must be agreed in a written amendment signed by both Parties.","type":"standard","order":1},{"id":"deliverables_milestones","title":"2. DELIVERABLES; MILESTONES; ACCEPTANCE","content":"2.1 Deliverables. Consultant will produce the following deliverables (the “Deliverables”): {{deliverables}}.\n\n2.2 Milestones and Schedule. The Parties will cooperate in good faith to establish milestones, target dates, and dependencies for the Deliverables. Any such milestones or schedules must be set forth in a written statement of work, project plan, or other written document signed (or acknowledged by email) by both Parties.\n\n2.3 Review and Acceptance. Unless otherwise specified in a signed statement of work:\n(a) Client will have a reasonable period after receipt to review each Deliverable.\n(b) Client will either accept the Deliverable in writing (including email) or provide written notice of specific, material nonconformities with the agreed requirements.\n(c) Consultant will use commercially reasonable efforts to correct such nonconformities and resubmit the Deliverable.\n\n2.4 Deemed Acceptance. If Client does not provide a rejection notice with specific, material nonconformities within a reasonable period after delivery, the Deliverable will be deemed accepted.\n\n2.5 Cooperation. Client acknowledges that successful delivery may require timely feedback and decisions by Client. Consultant will not be liable for failure to meet a target schedule to the extent delays are caused by Client or by events outside Consultant’s reasonable control.","type":"standard","order":2},{"id":"compensation","title":"3. COMPENSATION; INVOICING; EXPENSES; TAXES","content":"3.1 Fees. Client will pay Consultant as follows (choose or specify the applicable structure in an attachment or statement of work):\n(a) Fixed Fee: {{payment_amount}} for the Services; and/or\n(b) Hourly: {{hourly_rate}} per hour for time spent performing the Services.\n\n3.2 Deposit/Retainer (if applicable). Upon execution (or as otherwise specified in writing), Client will pay a deposit/retainer of {{deposit_amount}}. Unless otherwise stated in writing, the deposit/retainer will be applied against fees due.\n\n3.3 Invoicing and Payment. Consultant will invoice Client in accordance with the Parties’ written agreement (or, if not specified, monthly in arrears). Client will pay undisputed amounts within a commercially reasonable time after receipt of a valid invoice. The Parties may specify payment timing and methods in writing.\n\n3.4 Disputed Amounts. If Client disputes any portion of an invoice, Client will notify Consultant in writing within a reasonable time, describing the basis for the dispute in reasonable detail, and will timely pay any undisputed portion. The Parties will work in good faith to resolve disputes promptly.\n\n3.5 Expenses. Unless otherwise agreed in writing, Client will reimburse Consultant for reasonable, necessary, and pre-approved out-of-pocket expenses incurred in performing the Services. Consultant will provide reasonable documentation upon request.\n\n3.6 Taxes. Consultant is solely responsible for all taxes arising from compensation paid under this Agreement, including without limitation federal, state, and local income taxes and self-employment taxes. Client will not withhold taxes from payments to Consultant unless required by applicable law.\n\n3.7 No Other Benefits. Consultant is not entitled to participate in any Client employee benefit plan, fringe benefit, or similar program.\n\n3.8 Suspension for Nonpayment. If Client fails to pay undisputed amounts when due, Consultant may, after providing written notice and a reasonable opportunity to cure, suspend performance until payment is made. Any resulting schedule impacts will be treated as a change in scope/schedule.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM; TERMINATION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until {{expiration_date}} unless earlier terminated in accordance with this Section 4.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement for any reason upon {{notice_period}} days’ prior written notice to the other Party.\n\n4.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party materially breaches this Agreement and fails to cure such breach within a reasonable cure period after receiving written notice specifying the breach (except that no cure period is required for breaches that are not reasonably curable).\n\n4.4 Effect of Termination. Upon termination:\n(a) Consultant will cease performing the Services.\n(b) Client will pay Consultant for all Services performed through the effective date of termination, plus approved, unreimbursed expenses.\n(c) If fees are fixed-fee and the scope is partially completed, the Parties will determine in good faith the portion of the fixed fee earned based on work performed and Deliverables accepted or substantially completed.\n(d) Each Party will return or, at the disclosing Party’s option, securely destroy the other Party’s Confidential Information (as defined below), subject to Section 7.6 (Permitted Retention).\n\n4.5 Survival. The rights and obligations that by their nature should survive termination will survive, including without limitation Sections concerning compensation owed, intellectual property, confidentiality, limitation of liability, governing law, and general provisions.","type":"standard","order":4},{"id":"independent_contractor_ab5","title":"5. INDEPENDENT CONTRACTOR STATUS; CALIFORNIA COMPLIANCE (AB 5)","content":"5.1 Independent Contractor. Consultant is an independent contractor and not an employee, partner, joint venturer, agent, or representative of Client. Consultant is solely responsible for the manner and means of performing the Services, subject to the requirements of this Agreement.\n\n5.2 No Employment Relationship. Consultant is not eligible for, and hereby waives (to the extent permitted by law), any right to obtain, any Client employee benefits, including without limitation workers’ compensation (except as required by law), unemployment insurance, paid leave, retirement benefits, or health benefits.\n\n5.3 Control and Autonomy. Consultant retains the right to determine the method, details, and means of performing the Services; to set Consultant’s own work hours; and to perform services for others, provided that such activities do not materially interfere with Consultant’s performance under this Agreement or breach confidentiality obligations.\n\n5.4 Tools and Place of Work. Except as otherwise agreed in writing, Consultant will provide Consultant’s own tools, equipment, and workspace to perform the Services.\n\n5.5 Compliance with California “ABC Test” (AB 5). The Parties intend that Consultant’s relationship with Client be that of an independent contractor to the maximum extent permitted under applicable California law, including California Labor Code section 2775 et seq. (as amended) and related authorities. The Parties agree to structure their relationship consistent with the “ABC test” to the extent applicable, including that: (a) Consultant is free from Client’s control and direction in connection with performance of the Services (except as to the result); (b) Consultant performs the Services as an independently established business and may provide similar services to others; and (c) the Parties will cooperate in good faith to implement reasonable changes if required to comply with applicable law.\n\n5.6 No Restrictive Non-Compete. Nothing in this Agreement is intended to restrict Consultant from engaging in a lawful profession, trade, or business, except as may be required to protect Client’s Confidential Information and trade secrets under applicable law.\n\n5.7 Insurance (if applicable). If requested by Client and commercially reasonable for the Services, Consultant will maintain appropriate insurance coverage customary for the Services and provide evidence of such coverage.","type":"standard","order":5},{"id":"intellectual_property","title":"6. INTELLECTUAL PROPERTY; WORK PRODUCT","content":"6.1 Definitions.\n(a) “Work Product” means all Deliverables and other work product, materials, inventions, improvements, developments, discoveries, works of authorship, documentation, notes, reports, analyses, and other items (whether tangible or intangible) that are conceived, created, developed, authored, or reduced to practice by Consultant, alone or with others, in the course of performing the Services.\n(b) “Background IP” means intellectual property owned or controlled by a Party prior to the Effective Date or developed independently of this Agreement without use of the other Party’s Confidential Information.\n\n6.2 Ownership of Work Product.\n(a) Unless otherwise stated in a signed statement of work, and to the extent permitted by law, upon Client’s full payment of all amounts due for the applicable Work Product, Consultant hereby assigns to Client all right, title, and interest in and to the Work Product, including all associated intellectual property rights.\n(b) Consultant will execute (and cause Consultant’s personnel, if any, to execute) documents and take reasonable actions necessary to effectuate the assignment described above.\n\n6.3 License to Consultant Tools/Background IP. To the extent any Consultant Background IP is incorporated into the Work Product, Consultant grants to Client a nonexclusive, worldwide, royalty-free, perpetual (or if not permitted, for the maximum term allowed by law), transferable license (with the right to sublicense) to use, reproduce, modify, distribute, and create derivative works of such Background IP as incorporated, solely as necessary for Client to use and exploit the Work Product.\n\n6.4 Client Materials. Client retains all rights in materials, data, content, and other items provided by Client to Consultant (“Client Materials”). Client grants Consultant a limited, nonexclusive, revocable license to use Client Materials solely to perform the Services.\n\n6.5 Moral Rights. To the extent permitted under applicable law, Consultant waives and agrees not to assert any “moral rights” or similar rights in the Work Product against Client or Client’s successors and assigns.\n\n6.6 No Implied Licenses. Except as expressly set forth in this Agreement, no licenses or rights are granted by either Party.\n\n6.7 Open Source and Third-Party Materials. Consultant will not incorporate open source software or third-party materials into the Deliverables in a manner that would impose material obligations on Client (including copyleft obligations) without Client’s prior written consent.","type":"standard","order":6},{"id":"confidentiality_trade_secrets_ccpa","title":"7. CONFIDENTIALITY; TRADE SECRETS; DATA PRIVACY (CCPA)","content":"7.1 Definition of Confidential Information. “Confidential Information” means any nonpublic information disclosed by or on behalf of a Party (“Disclosing Party”) to the other Party (“Receiving Party”), whether disclosed orally, visually, electronically, or in writing, that is designated as confidential or that reasonably should be understood to be confidential given the nature of the information and the circumstances of disclosure. Confidential Information includes without limitation business plans, financial information, customer and vendor information, product plans, software, source code, security information, and trade secrets.\n\n7.2 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate by competent evidence: (a) is or becomes publicly available through no breach of this Agreement; (b) was lawfully known to the Receiving Party without restriction before receipt from the Disclosing Party; (c) is lawfully received from a third party without breach of any obligation; or (d) is independently developed by the Receiving Party without use of or reference to the Disclosing Party’s Confidential Information.\n\n7.3 Confidentiality Obligations. The Receiving Party will: (a) use the Disclosing Party’s Confidential Information solely to perform its obligations or exercise its rights under this Agreement; (b) not disclose such Confidential Information to any third party except as permitted under this Agreement; and (c) protect such Confidential Information using at least the same degree of care it uses to protect its own confidential information of like importance, and in no event less than reasonable care.\n\n7.4 Permitted Disclosures. The Receiving Party may disclose Confidential Information to its employees, contractors, professional advisors, and agents who have a need to know for purposes of this Agreement and who are bound by confidentiality obligations at least as protective as those herein. The Receiving Party remains responsible for any breach by such persons.\n\n7.5 Compelled Disclosure. If the Receiving Party is required by law, regulation, or court order to disclose Confidential Information, it will (to the extent legally permitted) provide prompt written notice to the Disclosing Party and reasonably cooperate (at the Disclosing Party’s expense) in seeking a protective order or other appropriate remedy. The Receiving Party will disclose only the minimum Confidential Information required.\n\n7.6 Permitted Retention. Notwithstanding the foregoing, a Receiving Party may retain copies of Confidential Information to the extent required by applicable law or its bona fide document retention policies, provided that any retained Confidential Information remains subject to this Agreement.\n\n7.7 Trade Secrets; CUTSA. The Parties acknowledge that Confidential Information may include trade secrets protected under the California Uniform Trade Secrets Act (California Civil Code sections 3426–3426.11) (“CUTSA”) and other applicable law. Unauthorized use or disclosure may cause irreparable harm. The Disclosing Party may seek injunctive or equitable relief in addition to any other remedies.\n\n7.8 Data Privacy; CCPA Considerations. To the extent Consultant receives, accesses, or processes “personal information” (as defined by the California Consumer Privacy Act of 2018, as amended by the CPRA) (“CCPA”) on behalf of Client in connection with the Services (“Client Personal Information”), Consultant will: (a) use such Client Personal Information solely for the business purpose of performing the Services and as otherwise permitted by the CCPA and this Agreement; (b) not sell or share Client Personal Information (as those terms are defined under the CCPA); (c) implement and maintain reasonable security procedures and practices appropriate to the nature of the information; and (d) notify Client without undue delay upon becoming aware of unauthorized access to Client Personal Information in Consultant’s possession or control.\n\n7.9 Return/Destruction. Upon request or termination, each Party will return or securely destroy the other Party’s Confidential Information as provided in Section 4.4(d), subject to Section 7.6.\n\n7.10 Publicity. Neither Party may use the other Party’s name, trademarks, or logos in press releases, marketing materials, or public announcements without the other Party’s prior written consent.","type":"standard","order":7},{"id":"representations_warranties","title":"8. REPRESENTATIONS; WARRANTIES; COMPLIANCE","content":"8.1 Mutual Representations. Each Party represents and warrants that: (a) it has full right, power, and authority to enter into and perform this Agreement; (b) this Agreement constitutes a legal, valid, and binding obligation enforceable against it in accordance with its terms; and (c) its execution and performance of this Agreement will not violate any other agreement to which it is bound.\n\n8.2 Consultant Representations. Consultant represents and warrants that:\n(a) Services will be performed in a professional and workmanlike manner consistent with Section 1.3.\n(b) Consultant will comply with all applicable laws, rules, and regulations in performing the Services.\n(c) To Consultant’s knowledge, the Work Product will not infringe or misappropriate any third-party intellectual property rights.\n(d) Consultant has and will maintain all licenses, permits, and qualifications required to perform the Services.\n\n8.3 Client Representations. Client represents and warrants that Client has the rights necessary to provide Client Materials to Consultant for use as contemplated in this Agreement.\n\n8.4 Disclaimer. EXCEPT AS EXPRESSLY PROVIDED IN THIS AGREEMENT, NEITHER PARTY MAKES ANY OTHER WARRANTIES, WHETHER EXPRESS, IMPLIED, STATUTORY, OR OTHERWISE, AND EACH PARTY SPECIFICALLY DISCLAIMS ALL IMPLIED WARRANTIES, INCLUDING ANY IMPLIED WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, AND NON-INFRINGEMENT, TO THE MAXIMUM EXTENT PERMITTED BY LAW.\n\n8.5 No Guaranteed Outcomes. Consultant does not guarantee any specific business, financial, legal, or regulatory outcome unless expressly stated in a signed writing by Consultant.","type":"standard","order":8},{"id":"limitation_of_liability","title":"9. LIMITATION OF LIABILITY","content":"9.1 Limitation of Types of Damages. TO THE MAXIMUM EXTENT PERMITTED BY LAW, IN NO EVENT WILL EITHER PARTY BE LIABLE TO THE OTHER FOR ANY INDIRECT, INCIDENTAL, CONSEQUENTIAL, SPECIAL, EXEMPLARY, OR PUNITIVE DAMAGES, OR FOR ANY LOSS OF PROFITS, REVENUE, BUSINESS, GOODWILL, OR DATA, ARISING OUT OF OR RELATED TO THIS AGREEMENT, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGES.\n\n9.2 Liability Cap. TO THE MAXIMUM EXTENT PERMITTED BY LAW, EACH PARTY’S TOTAL AGGREGATE LIABILITY ARISING OUT OF OR RELATED TO THIS AGREEMENT WILL NOT EXCEED THE TOTAL FEES PAID OR PAYABLE BY CLIENT TO CONSULTANT UNDER THIS AGREEMENT (INCLUDING ANY APPLICABLE STATEMENT OF WORK) DURING THE TWELVE (12) MONTHS PRECEDING THE EVENT GIVING RISE TO THE CLAIM.\n\n9.3 Exceptions. The limitations in this Section 9 will not apply to: (a) a Party’s indemnification obligations expressly set forth in this Agreement (if any are added by the Parties in writing); (b) a Party’s breach of the other Party’s intellectual property rights; (c) a Party’s breach of confidentiality obligations; (d) a Party’s gross negligence, willful misconduct, or fraud; or (e) liability that cannot be limited under applicable law.\n\n9.4 Allocation of Risk. The Parties acknowledge that the fees reflect the allocation of risk and that the limitations in this Agreement are an essential basis of the bargain.","type":"standard","order":9},{"id":"governing_law_venue","title":"10. GOVERNING LAW; VENUE","content":"10.1 Governing Law. This Agreement and any dispute arising out of or related to this Agreement will be governed by and construed in accordance with the laws of {{governing_jurisdiction}}, without regard to its conflict of laws principles.\n\n10.2 Venue; Jurisdiction. Subject to Section 10.3 (if applicable), the Parties agree that any action or proceeding arising out of or related to this Agreement will be brought in the state or federal courts located in California, and each Party irrevocably submits to the personal jurisdiction of such courts.\n\n10.3 Injunctive Relief. Each Party acknowledges that a breach of Sections 6 or 7 may cause irreparable harm for which monetary damages may be inadequate, and therefore the non-breaching Party may seek injunctive or equitable relief without the necessity of posting bond, in addition to any other remedies.\n\n10.4 California Non-Compete Policy. The Parties acknowledge California’s strong public policy favoring employee and contractor mobility and generally voiding non-compete restraints (e.g., California Business and Professions Code section 16600), and agree that this Agreement will be interpreted consistent with such policy.","type":"standard","order":10},{"id":"optional_non_compete","title":"11. OPTIONAL CLAUSE — NON-COMPETE (GENERALLY UNENFORCEABLE IN CALIFORNIA)","content":"11.1 Notice Regarding Enforceability. The Parties acknowledge and agree that, under California law, contractual provisions that restrain anyone from engaging in a lawful profession, trade, or business are generally void, with limited statutory exceptions. This Section 11 is included only if, and to the extent, it is enforceable under applicable law.\n\n11.2 No Broad Restraint. Except as permitted by applicable law and as narrowly tailored to protect Client’s trade secrets and Confidential Information, nothing in this Agreement prohibits Consultant from providing services to any other person or entity, including competitors of Client.\n\n11.3 Permitted Restriction (If Applicable). If and only to the extent enforceable under applicable law, Consultant agrees that during the term of this Agreement, Consultant will not use Client’s Confidential Information or trade secrets to provide substantially similar services to a direct competitor of Client in a manner that would reasonably be expected to cause disclosure or misuse of such Confidential Information or trade secrets.\n\n11.4 Severability and Reformation. If any portion of this Section 11 is found unenforceable, it will be severed and the remainder will be enforced to the maximum extent permitted by law, without expanding the restriction beyond what is lawful.","type":"optional","order":11},{"id":"general_provisions","title":"12. GENERAL PROVISIONS","content":"12.1 Notices. All notices under this Agreement must be in writing and will be deemed given when delivered personally, sent by confirmed email, sent by nationally recognized overnight courier, or mailed by certified mail (return receipt requested), to the addresses and emails below (or to any updated address/email provided by notice):\n(a) If to Client: {{party_a_company}}, Attn: {{party_a_name}}, {{party_a_title}}, {{party_a_address}}, Email: {{party_a_email}}.\n(b) If to Consultant: {{party_b_company}}, Attn: {{party_b_name}}, {{party_b_title}}, {{party_b_address}}, Email: {{party_b_email}}.\n\n12.2 Assignment. Neither Party may assign or transfer this Agreement, in whole or in part, without the prior written consent of the other Party, except that Client may assign this Agreement without consent in connection with a merger, acquisition, reorganization, or sale of substantially all of its assets, provided that the assignee assumes Client’s obligations in writing.\n\n12.3 Subcontracting. Consultant may not subcontract material portions of the Services without Client’s prior written consent. Consultant remains responsible for the acts and omissions of approved subcontractors.\n\n12.4 Entire Agreement. This Agreement, together with any exhibits, statements of work, or attachments referenced herein, constitutes the entire agreement between the Parties with respect to its subject matter and supersedes all prior and contemporaneous agreements, proposals, representations, and understandings, whether written or oral.\n\n12.5 Amendment; Waiver. Any amendment or modification to this Agreement must be in a writing signed by both Parties. Any waiver must be in writing and will be effective only to the extent expressly stated.\n\n12.6 Severability. If any provision of this Agreement is held invalid, illegal, or unenforceable, the remaining provisions will remain in full force and effect, and the Parties will substitute a valid provision that most closely reflects the original intent.\n\n12.7 Counterparts; Electronic Signatures. This Agreement may be executed in counterparts, each of which will be deemed an original and all of which together constitute one instrument. Signatures delivered electronically (including PDF or e-signature) are binding and effective.\n\n12.8 Force Majeure. Neither Party will be liable for delay or failure to perform due to events beyond its reasonable control, including acts of God, natural disasters, labor disputes, war, terrorism, civil unrest, government action, or failures of suppliers or networks not caused by the affected Party.\n\n12.9 Relationship of the Parties. The Parties are independent contracting parties. Nothing in this Agreement creates any partnership, joint venture, fiduciary, or agency relationship.\n\n12.10 No Third-Party Beneficiaries. This Agreement is for the sole benefit of the Parties and their permitted successors and assigns, and nothing herein confers any rights on any third party.\n\n12.11 Interpretation. Headings are for convenience only and do not affect interpretation. The words “including” and “include” mean “including without limitation.”\n\n12.12 Non-Disparagement (Optional; If Added). Any non-disparagement obligation must be set forth in a separate, specific written clause signed by both Parties; otherwise, none applies.\n\n12.13 Conflict with Statements of Work. If this Agreement conflicts with a signed statement of work, the statement of work will control only with respect to the specific Services described therein, and this Agreement will otherwise control.\n\n12.14 California-Specific Savings Clause. This Agreement will be interpreted and enforced to the maximum extent permitted by applicable California law. Any provision that is inconsistent with applicable law will be modified solely to the extent necessary to comply with such law.","type":"standard","order":12}]'::jsonb,
